import { Model, settings, ExpressionValidator } from "survey-core";

function assert(condition, message) {
  if (!condition) throw new Error(message);
}

function summarize(name, survey) {
  const valid = survey.validate(true);
  console.log(name, JSON.stringify({ valid, errors: survey.getAllQuestions().map(q => [q.name, q.errors.length]) }));
  return valid;
}

// Read-only required panel from the issue should not fail validation.
const readOnlyPanelSurvey = new Model({
  elements: [{ type: "panel", name: "panel1", readOnly: true, isRequired: true, elements: [{ type: "text", name: "q1" }] }]
});
assert(summarize("readOnlyPanel", readOnlyPanelSurvey) === true, "read-only required panel should be valid");
assert(readOnlyPanelSurvey.getPanelByName("panel1").errors.length === 0, "read-only panel should not have required errors");

// Editable required panel should still fail when all nested questions are empty.
const editablePanelSurvey = new Model({
  elements: [{ type: "panel", name: "panel1", isRequired: true, elements: [{ type: "text", name: "q1" }] }]
});
assert(summarize("editablePanel", editablePanelSurvey) === false, "editable required panel should still be invalid");
assert(editablePanelSurvey.getPanelByName("panel1").errors.length === 1, "editable panel should keep required error");

// Required panel inside a read-only parent inherits read-only and should not fail.
const parentReadOnlySurvey = new Model({
  elements: [{ type: "panel", name: "parent", readOnly: true, elements: [{ type: "panel", name: "child", isRequired: true, elements: [{ type: "text", name: "q1" }] }] }]
});
assert(summarize("parentReadOnlyPanel", parentReadOnlySurvey) === true, "child panel with read-only parent should be valid");
assert(parentReadOnlySurvey.getPanelByName("child").isReadOnly === true, "child panel should inherit read-only state");
assert(parentReadOnlySurvey.getPanelByName("child").errors.length === 0, "child panel should not have required errors");

// Required question with a read-only parent should skip required even when read-only validation is enabled.
settings.readOnly.enableValidation = true;
try {
  const readOnlyQuestionSurvey = new Model({
    elements: [{ type: "panel", name: "panel1", readOnly: true, elements: [{ type: "text", name: "q1", isRequired: true }] }]
  });
  assert(summarize("readOnlyQuestion", readOnlyQuestionSurvey) === true, "read-only required question should be valid");
  assert(readOnlyQuestionSurvey.getQuestionByName("q1").errors.length === 0, "read-only question should not have required errors");

  const validatorSurvey = new Model({ elements: [{ type: "text", name: "q1", readOnly: true, defaultValue: "value" }] });
  validatorSurvey.getQuestionByName("q1").validators.push(new ExpressionValidator("1 = 2"));
  assert(summarize("readOnlyNonRequiredValidator", validatorSurvey) === false, "non-required validator should still run when enabled");
  assert(validatorSurvey.getQuestionByName("q1").errors.length === 1, "validator error should remain enabled");
} finally {
  settings.readOnly.enableValidation = false;
}
